mapper.select:
SELECT mr.id, mr.registration_id, mr.patient_id, p.patient_name,
       mr.doctor_id, d.doctor_name,
       mr.chief_complaint, mr.present_illness, mr.diagnosis, mr.treatment_plan, mr.record_time
FROM medical_record mr
LEFT JOIN patient p ON mr.patient_id = p.id
LEFT JOIN doctor d ON mr.doctor_id = d.id

    AND mr.registration_id = #{registrationId}
    AND mr.patient_id = #{patientId}
    AND mr.doctor_id = #{doctorId}

        AND p.patient_name LIKE CONCAT('%', #{patientName}, '%')


ORDER BY mr.record_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM medical_record mr
LEFT JOIN patient p ON mr.patient_id = p.id

    AND mr.registration_id = #{registrationId}
    AND mr.patient_id = #{patientId}
    AND mr.doctor_id = #{doctorId}

        AND p.patient_name LIKE CONCAT('%', #{patientName}, '%')
